import{_ as a,c as s,o as e,a1 as l}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"スキル更新：スキルを最新に保つ | opencode-openskills","description":"OpenSkills updateコマンドを使用して、インストール済みのスキルを最新にする方法を学びます。全スキルの一括更新や指定スキルの更新をサポートし、ローカルパスとgitリポジトリの更新の違いを理解し、スキルを最新バージョンに保ちます。","frontmatter":{"title":"スキル更新：スキルを最新に保つ | opencode-openskills","sidebarTitle":"スキルをワンクリックで更新","subtitle":"スキル更新：スキルを最新に保つ","description":"OpenSkills updateコマンドを使用して、インストール済みのスキルを最新にする方法を学びます。全スキルの一括更新や指定スキルの更新をサポートし、ローカルパスとgitリポジトリの更新の違いを理解し、スキルを最新バージョンに保ちます。","tags":["skills","update","git"],"prerequisite":["start-installation","start-first-skill"],"order":5},"headers":[],"relativePath":"ja/numman-ali/openskills/platforms/update-skills/index.md","filePath":"ja/numman-ali/openskills/platforms/update-skills/index.md"}'),i={name:"ja/numman-ali/openskills/platforms/update-skills/index.md"};function d(n,t,o,r,p,h){return e(),s("div",null,[...t[0]||(t[0]=[l(`<h1 id="スキル更新-スキルをソースリポジトリと同期させる" tabindex="-1">スキル更新：スキルをソースリポジトリと同期させる <a class="header-anchor" href="#スキル更新-スキルをソースリポジトリと同期させる" aria-label="Permalink to &quot;スキル更新：スキルをソースリポジトリと同期させる&quot;">​</a></h1><h2 id="このレッスンでできること" tabindex="-1">このレッスンでできること <a class="header-anchor" href="#このレッスンでできること" aria-label="Permalink to &quot;このレッスンでできること&quot;">​</a></h2><p>このレッスンでは、OpenSkills スキルを常に最新バージョンに保つ方法を学びます。OpenSkills update コマンドを使用して、以下のことができるようになります：</p><ul><li>ワンクリックで全インストール済みスキルを更新</li><li>指定した複数のスキルのみを更新</li><li>異なるインストール元による更新の違いを理解</li><li>更新失敗の原因をトラブルシューティング</li></ul><h2 id="現在直面している問題" tabindex="-1">現在直面している問題 <a class="header-anchor" href="#現在直面している問題" aria-label="Permalink to &quot;現在直面している問題&quot;">​</a></h2><p>スキルリポジトリは絶えず更新されています——作成者がバグを修正し、新機能を追加し、ドキュメントを改善しています。しかし、あなたがインストールしたスキルは古いバージョンのままです。</p><p>既にこのような状況に遭遇したことがあるかもしれません：</p><ul><li>スキルドキュメントには「ある機能をサポート」と書かれているが、AIエージェントは「わからない」と言う</li><li>スキルでより良いエラーメッセージが更新されたが、あなたが見ているのはまだ古いもの</li><li>インストール時のバグは修正されたが、まだ影響を受けている</li></ul><p><strong>毎回削除して再インストールするのは面倒です</strong>——効率的な更新方法が必要です。</p><h2 id="いつこの機能を使うか" tabindex="-1">いつこの機能を使うか <a class="header-anchor" href="#いつこの機能を使うか" aria-label="Permalink to &quot;いつこの機能を使うか&quot;">​</a></h2><p><code>update</code> コマンドを使用する典型的なシーン：</p><table tabindex="0"><thead><tr><th>シーン</th><th>操作</th></tr></thead><tbody><tr><td>スキルに更新があると気づく</td><td><code>openskills update</code> を実行</td></tr><tr><td>数個のスキルのみ更新したい</td><td><code>openskills update skill1,skill2</code></td></tr><tr><td>ローカル開発スキルのテスト</td><td>ローカルパスから更新</td></tr><tr><td>GitHubリポジトリから更新</td><td>自動で最新コードをgit clone</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">更新頻度の推奨</p><ul><li><strong>コミュニティスキル</strong>：毎月1回更新し、最新の改善を取得</li><li><strong>自分で開発したスキル</strong>：修正のたびに手動で更新</li><li><strong>ローカルパススキル</strong>：コードを修正するたびに更新</li></ul></div><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><p>始める前に、以下が完了していることを確認してください：</p><ul><li>[x] OpenSkillsがインストール済み（<a href="./../../start/installation/">OpenSkillsのインストール</a>を参照）</li><li>[x] 少なくとも1つのスキルがインストール済み（<a href="./../../start/first-skill/">最初のスキルをインストール</a>を参照）</li><li>[x] GitHubからインストールした場合、ネットワーク接続があることを確認</li></ul><h2 id="核心アイデア" tabindex="-1">核心アイデア <a class="header-anchor" href="#核心アイデア" aria-label="Permalink to &quot;核心アイデア&quot;">​</a></h2><p>OpenSkills の更新メカニズムは非常にシンプルです：</p><p><strong>インストール時にソース情報を記録 → 更新時に元のソースから再コピー</strong></p><div class="info custom-block"><p class="custom-block-title">再インストールが必要な理由</p><p>古いバージョンのスキル（インストール時にソースが記録されていない）は更新できません。この場合、一度再インストールする必要があります。OpenSkills がソースを記憶し、その後は自動的に更新できるようになります。</p></div><p><strong>3種類のインストール元の更新方法</strong>：</p><table tabindex="0"><thead><tr><th>ソースタイプ</th><th>更新方法</th><th>適用シーン</th></tr></thead><tbody><tr><td><strong>ローカルパス</strong></td><td>ローカルパスから直接コピー</td><td>自分のスキルを開発中</td></tr><tr><td><strong>gitリポジトリ</strong></td><td>最新コードを一時ディレクトリにクローン</td><td>GitHub/GitLabからインストール</td></tr><tr><td><strong>GitHub shorthand</strong></td><td>完全URLに変換してクローン</td><td>GitHub公式リポジトリからインストール</td></tr></tbody></table><p>更新時、ソースメタデータがないスキルはスキップされ、再インストールが必要なスキル名がリスト表示されます。</p><h2 id="実践してみよう" tabindex="-1">実践してみよう <a class="header-anchor" href="#実践してみよう" aria-label="Permalink to &quot;実践してみよう&quot;">​</a></h2><h3 id="ステップ1-インストール済みスキルを確認" tabindex="-1">ステップ1：インストール済みスキルを確認 <a class="header-anchor" href="#ステップ1-インストール済みスキルを確認" aria-label="Permalink to &quot;ステップ1：インストール済みスキルを確認&quot;">​</a></h3><p>まず、どのスキルを更新できるか確認しましょう：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>表示されるもの</strong>：インストール済みスキルのリスト（名前、説明、インストール場所のタグ（project/global）を含む）</p><h3 id="ステップ2-全スキルを更新" tabindex="-1">ステップ2：全スキルを更新 <a class="header-anchor" href="#ステップ2-全スキルを更新" aria-label="Permalink to &quot;ステップ2：全スキルを更新&quot;">​</a></h3><p>最もシンプルな方法は、インストール済みの全スキルを更新することです：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>表示されるもの</strong>：スキルを1つずつ更新し、各スキルの更新結果を表示</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Skipped: my-old-skill (no source metadata; re-install once to enable updates)</span></span>
<span class="line"><span>Summary: 2 updated, 1 skipped (3 total)</span></span></code></pre></div><details class="details custom-block"><summary>スキップされたスキルの意味</summary><p><code>Skipped: xxx (no source metadata)</code> と表示された場合、このスキルは更新機能が追加される前にインストールされたことを意味します。自動更新を有効にするには、一度再インストールする必要があります。</p></details><h3 id="ステップ3-指定したスキルを更新" tabindex="-1">ステップ3：指定したスキルを更新 <a class="header-anchor" href="#ステップ3-指定したスキルを更新" aria-label="Permalink to &quot;ステップ3：指定したスキルを更新&quot;">​</a></h3><p>特定の数個のスキルのみを更新したい場合、スキル名を（カンマ区切りで）指定します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-workflow,check-branch-first</span></span></code></pre></div><p><strong>表示されるもの</strong>：指定された2つのスキルのみが更新される</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Summary: 2 updated, 0 skipped (2 total)</span></span></code></pre></div><h3 id="ステップ4-ローカル開発中のスキルを更新" tabindex="-1">ステップ4：ローカル開発中のスキルを更新 <a class="header-anchor" href="#ステップ4-ローカル開発中のスキルを更新" aria-label="Permalink to &quot;ステップ4：ローカル開発中のスキルを更新&quot;">​</a></h3><p>ローカルでスキルを開発中の場合、ローカルパスから更新できます：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span></span></code></pre></div><p><strong>表示されるもの</strong>：スキルがインストール時のローカルパスから再コピーされる</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: my-skill</span></span>
<span class="line"><span>Summary: 1 updated, 0 skipped (1 total)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">ローカル開発ワークフロー</p><p>開発プロセス：</p><ol><li>スキルをインストール：<code>openskills install ./my-skill</code></li><li>コードを修正</li><li>スキルを更新：<code>openskills update my-skill</code></li><li>AGENTS.mdに同期：<code>openskills sync</code></li></ol></div><h3 id="ステップ5-更新失敗を処理" tabindex="-1">ステップ5：更新失敗を処理 <a class="header-anchor" href="#ステップ5-更新失敗を処理" aria-label="Permalink to &quot;ステップ5：更新失敗を処理&quot;">​</a></h3><p>一部のスキルの更新が失敗した場合、OpenSkills は詳細な理由を表示します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>表示される可能性のある状況</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skipped: git-workflow (git clone failed)</span></span>
<span class="line"><span>Skipped: my-skill (local source missing)</span></span>
<span class="line"><span>Missing source metadata (1): old-skill</span></span>
<span class="line"><span>Clone failed (1): git-workflow</span></span></code></pre></div><p><strong>対応する解決方法</strong>：</p><table tabindex="0"><thead><tr><th>エラーメッセージ</th><th>原因</th><th>解決方法</th></tr></thead><tbody><tr><td><code>no source metadata</code></td><td>古いバージョンのインストール</td><td>再インストール：<code>openskills install &lt;source&gt;</code></td></tr><tr><td><code>local source missing</code></td><td>ローカルパスが削除された</td><td>ローカルパスを復元または再インストール</td></tr><tr><td><code>SKILL.md missing at local source</code></td><td>ローカルファイルが削除された</td><td>SKILL.mdファイルを復元</td></tr><tr><td><code>git clone failed</code></td><td>ネットワーク問題またはリポジトリが存在しない</td><td>ネットワークまたはリポジトリアドレスを確認</td></tr><tr><td><code>SKILL.md not found in repo</code></td><td>リポジトリ構造が変更された</td><td>スキル作成者に連絡するかsubpathを更新</td></tr></tbody></table><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下ができるようになったことを確認してください：</p><ul><li>[ ] <code>openskills update</code> を使用して全スキルを更新できる</li><li>[ ] カンマ区切りで指定したスキルを更新できる</li><li>[ ] 「スキップ」されたスキルの意味と解決方法を理解している</li><li>[ ] ローカル開発スキルの更新プロセスを理解している</li></ul><h2 id="注意すべき点" tabindex="-1">注意すべき点 <a class="header-anchor" href="#注意すべき点" aria-label="Permalink to &quot;注意すべき点&quot;">​</a></h2><h3 id="❌-よくある間違い" tabindex="-1">❌ よくある間違い <a class="header-anchor" href="#❌-よくある間違い" aria-label="Permalink to &quot;❌ よくある間違い&quot;">​</a></h3><table tabindex="0"><thead><tr><th>間違い</th><th>正しいアプローチ</th></tr></thead><tbody><tr><td>スキップされたまま放置する</td><td>プロンプトに従って再インストールまたは問題を修正する</td></tr><tr><td>毎回削除して再インストールする</td><td><code>update</code> コマンドを使用する方が効率的</td></tr><tr><td>どこからインストールしたか知らない</td><td><code>openskills list</code> でソースを確認</td></tr></tbody></table><h3 id="⚠️-注意事項" tabindex="-1">⚠️ 注意事項 <a class="header-anchor" href="#⚠️-注意事項" aria-label="Permalink to &quot;⚠️ 注意事項&quot;">​</a></h3><p><strong>更新はローカル修正を上書きします</strong></p><p>インストールディレクトリ内のスキルファイルを直接修正した場合、更新時にこれらの修正は上書きされます。正しいアプローチは以下の通りです：</p><ol><li><strong>ソースファイル</strong>（ローカルパスまたはリポジトリ）を修正する</li><li>その後 <code>openskills update</code> を実行</li></ol><p><strong>シンボリックリンクスキルは特別な処理が必要</strong></p><p>スキルがシンボリックリンクを通じてインストールされている場合（<a href="./../../advanced/symlink-support/">シンボリックリンクサポート</a>を参照）、更新はリンクを再作成し、シンボリックリンク関係は破壊されません。</p><p><strong>グローバルとプロジェクトスキルはそれぞれ更新が必要</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># プロジェクトスキルのみ更新（デフォルト）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># グローバルスキルは別途処理が必要</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># または --universal モードで統一管理</span></span></code></pre></div><h2 id="レッスンのまとめ" tabindex="-1">レッスンのまとめ <a class="header-anchor" href="#レッスンのまとめ" aria-label="Permalink to &quot;レッスンのまとめ&quot;">​</a></h2><p>このレッスンでは、OpenSkills の更新機能を学びました：</p><ul><li><strong>一括更新</strong>：<code>openskills update</code> で全スキルをワンクリック更新</li><li><strong>指定更新</strong>：<code>openskills update skill1,skill2</code> で特定のスキルを更新</li><li><strong>ソース認識</strong>：ローカルパスとgitリポジトリを自動認識</li><li><strong>エラーメッセージ</strong>：スキップの理由と解決方法を詳細に説明</li></ul><p>更新機能によりスキルを最新バージョンに保ち、使用しているスキルが常に最新の改善と修正を含んでいることを保証します。</p><h2 id="次のレッスン预告" tabindex="-1">次のレッスン预告 <a class="header-anchor" href="#次のレッスン预告" aria-label="Permalink to &quot;次のレッスン预告&quot;">​</a></h2><blockquote><p>次のレッスンでは、<strong><a href="./../remove-skills/">スキルの削除</a></strong> を学びます。</p><p>学べること：</p><ul><li>インタラクティブな <code>manage</code> コマンドを使用してスキルを削除する方法</li><li><code>remove</code> コマンドを使用してスクリプト化された削除を行う方法</li><li>スキル削除後の注意点</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>スキル更新メインロジック</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L14-L150" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>14-150</td></tr><tr><td>ローカルパス更新</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L64-L82" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>64-82</td></tr><tr><td>Gitリポジトリ更新</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L85-L125" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>85-125</td></tr><tr><td>ディレクトリからスキルをコピー</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L152-L163" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>152-163</td></tr><tr><td>パスセキュリティ検証</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L165-L172" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>165-172</td></tr><tr><td>メタデータ構造定義</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L8-L15" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>8-15</td></tr><tr><td>スキルメタデータの読み取り</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L17-L27" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>17-27</td></tr><tr><td>スキルメタデータの書き込み</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L29-L36" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>29-36</td></tr><tr><td>CLIコマンド定義</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/cli.ts#L58-L62" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>58-62</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>SKILL_METADATA_FILE = &#39;.openskills.json&#39;</code>：メタデータファイル名、スキルのインストール元を記録</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>updateSkills(skillNames)</code>：指定または全スキルを更新するメイン関数</li><li><code>updateSkillFromDir(targetPath, sourceDir)</code>：ソースディレクトリからスキルをターゲットディレクトリにコピー</li><li><code>isPathInside(targetPath, targetDir)</code>：インストールパスのセキュリティを検証（パストラバーサルを防止）</li><li><code>readSkillMetadata(skillDir)</code>：スキルのメタデータを読み取る</li><li><code>writeSkillMetadata(skillDir, metadata)</code>：スキルのメタデータを書き込み/更新</li></ul><p><strong>ビジネスルール</strong>：</p><ul><li><strong>BR-5-1</strong>：デフォルトで全インストール済みスキルを更新（update.ts:37-38）</li><li><strong>BR-5-2</strong>：カンマ区切りのスキル名リストをサポート（update.ts:15）</li><li><strong>BR-5-3</strong>：ソースメタデータがないスキルをスキップ（update.ts:56-62）</li><li><strong>BR-5-4</strong>：ローカルパスからの更新をサポート（update.ts:64-82）</li><li><strong>BR-5-5</strong>：gitリポジトリからの更新をサポート（update.ts:85-125）</li><li><strong>BR-5-6</strong>：パスセキュリティを検証（update.ts:156-162）</li></ul></details>`,75)])])}const u=a(i,[["render",d]]);export{k as __pageData,u as default};
